class Solution {
public:
    bool isFascinating(int n) {
        int concatenated = n * 1000000000 + 2 * n * 1000000 + 3 * n;
        std::string str = std::to_string(concatenated);
        std::sort(str.begin(), str.end());
        return str == "123456789";
    }
};
